import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"中国人民革命军事博物馆","description":"","frontmatter":{},"headers":[],"relativePath":"museums/military.md","filePath":"museums/military.md","lastUpdated":null}'),n={name:"museums/military.md"};function d(s,t,i,o,g,h){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="中国人民革命军事博物馆" tabindex="-1">中国人民革命军事博物馆 <a class="header-anchor" href="#中国人民革命军事博物馆" aria-label="Permalink to &quot;中国人民革命军事博物馆&quot;">​</a></h1><blockquote><p>&quot;了解中国军事历史的最佳场所。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>中国人民革命军事博物馆（简称军博）位于北京市海淀区，是中国唯一的大型综合性军事博物馆，也是中国第一个综合类军事博物馆。军博筹建于1958年，1960年正式对外开放。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">9:00-17:00（周一闭馆）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费（需预约）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">3-4小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁1号线/9号线军事博物馆站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市海淀区复兴路9号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="筹建" tabindex="-1">筹建 <a class="header-anchor" href="#筹建" aria-label="Permalink to &quot;筹建&quot;">​</a></h3><p>1958年，为庆祝中华人民共和国建国10周年，中共中央决定筹建军事博物馆。1958年9月，军事博物馆正式破土动工。</p><h3 id="开放" tabindex="-1">开放 <a class="header-anchor" href="#开放" aria-label="Permalink to &quot;开放&quot;">​</a></h3><p>1960年8月，军事博物馆正式对外开放，成为当时全国最大的博物馆。</p><h3 id="改扩建" tabindex="-1">改扩建 <a class="header-anchor" href="#改扩建" aria-label="Permalink to &quot;改扩建&quot;">​</a></h3><p>2012年至2017年，军事博物馆进行了大规模改扩建，2017年7月重新对外开放。新馆建筑面积从原先的6万平方米扩大到15.3万平方米。</p><h2 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h2><h3 id="外观" tabindex="-1">外观 <a class="header-anchor" href="#外观" aria-label="Permalink to &quot;外观&quot;">​</a></h3><p>军事博物馆建筑气势恢宏，正门上方悬挂着毛泽东主席题写的&quot;中国人民革命军事博物馆&quot;匾额。</p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">数据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>建筑面积</strong></td><td style="text-align:left;">15.3万平方米</td></tr><tr><td style="text-align:left;"><strong>陈列面积</strong></td><td style="text-align:left;">近6万平方米</td></tr><tr><td style="text-align:left;"><strong>主楼高度</strong></td><td style="text-align:left;">94.7米</td></tr><tr><td style="text-align:left;"><strong>结构</strong></td><td style="text-align:left;">塔座式建筑</td></tr></tbody></table><h3 id="主楼" tabindex="-1">主楼 <a class="header-anchor" href="#主楼" aria-label="Permalink to &quot;主楼&quot;">​</a></h3><p>主楼采用塔座式建筑，顶部是解放军军徽，高达94.7米，是北京的标志性建筑之一。</p><h2 id="常设展览" tabindex="-1">常设展览 <a class="header-anchor" href="#常设展览" aria-label="Permalink to &quot;常设展览&quot;">​</a></h2><h3 id="中国共产党领导的革命战争陈列" tabindex="-1">中国共产党领导的革命战争陈列 <a class="header-anchor" href="#中国共产党领导的革命战争陈列" aria-label="Permalink to &quot;中国共产党领导的革命战争陈列&quot;">​</a></h3><p>这是军博的基本陈列，全面展示中国共产党领导人民军队进行的革命战争。</p><h4 id="展示内容" tabindex="-1">展示内容 <a class="header-anchor" href="#展示内容" aria-label="Permalink to &quot;展示内容&quot;">​</a></h4><ul><li><strong>土地革命战争</strong>：南昌起义、秋收起义、红军长征等</li><li><strong>抗日战争</strong>：敌后抗战、重大战役等</li><li><strong>解放战争</strong>：三大战役、渡江战役等</li><li><strong>抗美援朝战争</strong>：抗美援朝战争全过程</li></ul><h3 id="兵器陈列" tabindex="-1">兵器陈列 <a class="header-anchor" href="#兵器陈列" aria-label="Permalink to &quot;兵器陈列&quot;">​</a></h3><p>兵器陈列是军博的特色展览，展示各时期兵器装备。</p><table tabindex="0"><thead><tr><th style="text-align:left;">展区</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>古代战争馆</strong></td><td style="text-align:left;">中国古代兵器</td></tr><tr><td style="text-align:left;"><strong>近代战争馆</strong></td><td style="text-align:left;">中国近代兵器</td></tr><tr><td style="text-align:left;"><strong>土地革命战争馆</strong></td><td style="text-align:left;">红军时期的兵器</td></tr><tr><td style="text-align:left;"><strong>抗日战争馆</strong></td><td style="text-align:left;">抗战时期的兵器</td></tr><tr><td style="text-align:left;"><strong>解放战争馆</strong></td><td style="text-align:left;">解放战争时期的兵器</td></tr><tr><td style="text-align:left;"><strong>兵器馆</strong></td><td style="text-align:left;">各种武器装备</td></tr></tbody></table><h3 id="大型兵器装备" tabindex="-1">大型兵器装备 <a class="header-anchor" href="#大型兵器装备" aria-label="Permalink to &quot;大型兵器装备&quot;">​</a></h3><p>军博广场上陈列着大型兵器装备，是军事爱好者的最爱。</p><table tabindex="0"><thead><tr><th style="text-align:left;">装备</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>轰-6轰炸机</strong></td><td style="text-align:left;">中国第一代轰炸机</td></tr><tr><td style="text-align:left;"><strong>东风-1导弹</strong></td><td style="text-align:left;">中国第一枚导弹</td></tr><tr><td style="text-align:left;"><strong>坦克</strong></td><td style="text-align:left;">各型坦克</td></tr><tr><td style="text-align:left;"><strong>火炮</strong></td><td style="text-align:left;">各型火炮</td></tr><tr><td style="text-align:left;"><strong>舰艇</strong></td><td style="text-align:left;">导弹艇等</td></tr></tbody></table><h3 id="军事科技陈列" tabindex="-1">军事科技陈列 <a class="header-anchor" href="#军事科技陈列" aria-label="Permalink to &quot;军事科技陈列&quot;">​</a></h3><p>展示中国军事科技的发展历程，包括导弹、航天、核武器等。</p><h2 id="珍贵文物" tabindex="-1">珍贵文物 <a class="header-anchor" href="#珍贵文物" aria-label="Permalink to &quot;珍贵文物&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">文物</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>南昌起义时朱德使用的手枪</strong></td><td style="text-align:left;">打响武装反抗第一枪</td></tr><tr><td style="text-align:left;"><strong>红军长征时的武器</strong></td><td style="text-align:left;">见证长征艰辛</td></tr><tr><td style="text-align:left;"><strong>抗日战争时期缴获的日军武器</strong></td><td style="text-align:left;">抗战战利品</td></tr><tr><td style="text-align:left;"><strong>解放战争时期的坦克</strong></td><td style="text-align:left;">从国民党军队缴获</td></tr><tr><td style="text-align:left;"><strong>抗美援朝战争的战利品</strong></td><td style="text-align:left;">美军装备</td></tr><tr><td style="text-align:left;"><strong>中国第一颗原子弹、氢弹模型</strong></td><td style="text-align:left;">两弹一星</td></tr><tr><td style="text-align:left;"><strong>中国第一颗人造卫星模型</strong></td><td style="text-align:left;">东方红一号</td></tr></tbody></table><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="预约须知" tabindex="-1">预约须知 <a class="header-anchor" href="#预约须知" aria-label="Permalink to &quot;预约须知&quot;">​</a></h3><ol><li><strong>提前预约</strong>：必须提前在官网或微信预约</li><li><strong>实名制</strong>：需携带身份证</li><li><strong>周一闭馆</strong>：注意开放时间</li></ol><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>经典路线（约3-4小时）</strong>：</p><p>室外大型兵器 → 革命战争陈列 → 兵器陈列 → 军事科技陈列 → 专题展览</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">1号线/9号线军事博物馆站A口</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">1路、4路、52路、65路等军事博物馆站</td></tr><tr><td style="text-align:left;">自驾</td><td style="text-align:left;">博物馆有停车场</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>提前预约</strong>：必须提前预约</li><li><strong>室外展区</strong>：先参观室外大型兵器</li><li><strong>讲解服务</strong>：可租借语音导览</li><li><strong>餐饮</strong>：馆内有餐厅</li><li><strong>军迷必去</strong>：军事爱好者的天堂</li><li><strong>结合游览</strong>：可与首博一起游览</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">首都博物馆</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">北京历史文化</td></tr><tr><td style="text-align:left;">中华世纪坛</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">文化建筑</td></tr><tr><td style="text-align:left;">玉渊潭公园</td><td style="text-align:center;">步行20分钟</td><td style="text-align:left;">樱花名园</td></tr><tr><td style="text-align:left;">北京西站</td><td style="text-align:center;">地铁1站</td><td style="text-align:left;">火车站</td></tr><tr><td style="text-align:left;">中央电视台</td><td style="text-align:center;">地铁2站</td><td style="text-align:left;">现代建筑</td></tr></tbody></table><hr><p><strong>📍 地址</strong>：北京市海淀区复兴路9号 <strong>📞 电话</strong>：010-66848606 <strong>🌐 官网</strong>：<a href="http://www.jb.mil.cn" target="_blank" rel="noreferrer">www.jb.mil.cn</a><strong>📱 预约</strong>：关注&quot;中国人民革命军事博物馆&quot;微信公众号预约</p>',48)])])}const y=e(n,[["render",d]]);export{f as __pageData,y as default};
